def should_draw(current, target, deck):
    if not deck:
        return "HOLD"
    n = len(deck)
    ev = 0.0
    for card in deck:
        new_total = current + card
        if new_total <= target:
            ev += new_total
    ev /= n
    if ev >= current:
        return "DRAW"
    else:
        return "HOLD"

